from llama_stack import LlamaStackSafetyShield

class SafetyFalsePositiveDetector:
    def __init__(self):
        self.benign_patterns = [
            'financial analysis',
            'market trends',
            'price comparison'
        ]

    def detect(self, shield_response):
        if shield_response.blocked and shield_response.reason == 'financial_advice':
            content_lower = shield_response.content.lower()
            if any(pattern in content_lower for pattern in self.benign_patterns):
                return {'issue': 'false_positive', 'confidence': 0.92}
        return None

from llama_stack import LlamaAgentLoop

class LoopExhaustionDetector:
    def __init__(self, progress_threshold=0.1):
        self.progress_threshold = progress_threshold

    def detect(self, loop_stats):
        turns_used = loop_stats.current_turn
        max_turns = loop_stats.max_turns
        progress = loop_stats.task_progress

        if turns_used / max_turns > 0.8 and progress < self.progress_threshold:
            return {
                'issue': 'loop_exhaustion',
                'turns_remaining': max_turns - turns_used,
                'progress_stalled': True
            }
        return None

from pydantic import BaseModel, ValidationError
from llama_stack import LlamaToolExecutor

class PriceCheckSchema(BaseModel):
    price: float
    is_valid: bool

class ToolSchemaDetector:
    def __init__(self):
        self.schemas = {'price_check': PriceCheckSchema}

    def detect(self, tool_response):
        schema_name = tool_response.tool_name
        if schema_name in self.schemas:
            try:
                self.schemas[schema_name](**tool_response.result)
            except ValidationError as e:
                return {
                    'issue': 'schema_violation',
                    'tool': schema_name,
                    'errors': [str(err) for err in e.errors()]
                }
        return None

