from llama_stack import LlamaAgentLoop

class AdaptiveAgentLoop(LlamaAgentLoop):
    def __init__(self, *args, stall_threshold=3, **kwargs):
        super().__init__(*args, **kwargs)
        self.stall_counter = 0
        self.last_progress = 0
        self.stall_threshold = stall_threshold

    def should_terminate(self):
        current_progress = self.task_progress
        if current_progress == self.last_progress:
            self.stall_counter += 1
        else:
            self.stall_counter = 0
        self.last_progress = current_progress

        return (self.stall_counter >= self.stall_threshold or 
                super().should_terminate())

from pydantic import BaseModel, field_validator
from llama_stack import LlamaToolExecutor

class SafePriceChecker(BaseModel):
    price: float
    is_valid: bool

    @field_validator('price', mode='before')
    @classmethod
    def coerce_price(cls, v):
        if isinstance(v, str):
            return float(v.replace('$', '').replace(',', ''))
        return float(v)

class SchemaToolWrapper:
    def __init__(self):
        self.executor = LlamaToolExecutor()
        self.schemas = {'price_check': SafePriceChecker}

    def execute(self, tool_name, params):
        raw_result = self.executor.execute(tool_name, params)
        schema = self.schemas.get(tool_name)
        if schema:
            return schema(**raw_result).model_dump()
        return raw_result
